package be.schaubroeck.lpb.rkm.rekenmotor.bv;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.WerkbonusGepensioneerdActief;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.WerkbonusGepensioneerdOpdracht;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.WerkbonusGepensioneerdOpper;
import be.schaubroeck.lpb.rkm.rekenmotor.util.CheckRegime;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementChecker;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

@AllArgsConstructor
public class BvPensioenZorgSector {

    private static final BigDecimal PERCENTAGE = new BigDecimal("0.33");

    public BvPensioenZorgSector(RekenBvKey bvKey, LocalDate taxDatum, ConstantManager constantManager) {
        this.bvKey = bvKey;
        this.checkRegime = new CheckRegime(taxDatum, bvKey);
        this.checkOpdracht = new WerkbonusGepensioneerdOpdracht();
        this.checkOpper = new WerkbonusGepensioneerdOpper(constantManager);
    }

    private final RekenBvKey bvKey;
    private final LoonElementChecker checkRegime;
    private final WerkbonusGepensioneerdOpdracht checkOpdracht;
    private final WerkbonusGepensioneerdOpper checkOpper;

    public void behandel(RekenContext context) {
        RekenTijd rekenTijd = context.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        if (WerkbonusGepensioneerdActief.isActief(rekenTijd)) {
            Persoon persoon = context.getUnchecked(RekenChainKey.PERSOON_KEY);
            for (Opdracht opdracht : persoon.getOpdrachten()) {
                RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
                behandelOpdracht(opdrachtContext, opdracht);
            }
        }
    }

    private void behandelOpdracht(RekenContext opdrachtContext, Opdracht opdracht) {
        if (checkOpdracht.komtInAanMerking(opdrachtContext, opdracht)) {
            Collection<LoonElement> elementen = getOpperElementenInAanmerking(opdrachtContext, opdracht);
            Money bbOpdracht = getBelastbaar(elementen);
            Money bv = getBedrijfsvoorheffing(elementen);
            Money verminderingBv = getVerminderingBvWerkbonus(elementen);
            Money berekendeBv = bv.subtract(verminderingBv);
            Money bvPercentage = bbOpdracht.multiply(PERCENTAGE).round(2);
            if (berekendeBv.compareTo(bvPercentage) > 0) {
                herverdeelBedrijfsvoorheffing(bvPercentage.add(verminderingBv), bbOpdracht, elementen);
            }
        }
    }


    private Collection<LoonElement> getOpperElementenInAanmerking(RekenContext opdrachtContext, Opdracht opdracht) {
        LoonElementManager manager = opdrachtContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(REKENTIJD_KEY);
        Collection<LoonElement> opdrachtElementen = LoonElement.createSortedSet();
        for (Opper opper : opdracht.getOpperSlices()) {
            if (checkOpper.komtInAanMerking(opper, rekenTijd)) {
                opdrachtElementen.addAll(manager.getOpperElementen(opper));
            }
        }
        return opdrachtElementen;
    }

    private Money getBedrijfsvoorheffing(Collection<LoonElement> loonElementen) {
        return RekenTools.getSomProperty(bvKey, loonElementen);
    }

    private Money getVerminderingBvWerkbonus(Collection<LoonElement> loonElementen) {
        if (bvKey == BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY) {
            Money verminderingWerkbonus = RekenTools.getSomProperty(VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY, loonElementen);
            Money verminderingWerkbonusB = RekenTools.getSomProperty(VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY, loonElementen);
            return verminderingWerkbonus.add(verminderingWerkbonusB);
        } else {
            return Money.ZERO;
        }
    }

    private void herverdeelBedrijfsvoorheffing(Money bedrijfsvoorheffing, Money totaalBelastbaar, Collection<LoonElement> loonElementen) {
        RekenTools.deleteKey(loonElementen, bvKey);
        BedragVerdelerFactory.verdeelBedragVolgensBasisPut(bvKey, bedrijfsvoorheffing, BELASTBAAR_KEY, totaalBelastbaar,
                loonElementen, checkRegime);
    }

    private Money getBelastbaar(Collection<LoonElement> loonElementen) {
        return RekenTools.getSomProperty(BELASTBAAR_KEY, loonElementen, checkRegime);
    }


}
